		private class WaitAndSetOnce : IDisposable
		{
			private readonly ManualResetEvent _evt;

			private int _hasSet;

			public WaitAndSetOnce()
			{
				_evt = new ManualResetEvent(initialState: false);
			}

			public void Set()
			{
				if (Interlocked.Exchange(ref _hasSet, 1) == 0)
				{
					_evt.Set();
				}
			}

			public void WaitOne()
			{
				_evt.WaitOne();
			}

			public void Dispose()
			{
				_evt.Dispose();
			}
		}

