				{
					evt.Set();
				});
				using (source.SubscribeSafe(observer))
				{
					evt.WaitOne();
				}
				observer.Error.ThrowIfNotNull();
			}
			finally
			{
				if (evt != null)
				{
					((IDisposable)evt).Dispose();
				}
			}
		}

