					}
				}, this, CancellationToken.None, TaskContinuationOptions.OnlyOnRanToCompletion | TaskContinuationOptions.ExecuteSynchronously, scheduler._taskFactory.Scheduler);
			}

			public void Dispose()
			{
				Disposable.TryDispose(ref _cancel);
			}
		}

