	public sealed class ThreadPoolScheduler : LocalScheduler, ISchedulerLongRunning, ISchedulerPeriodic
	{
		private sealed class FastPeriodicTimer<TState> : IDisposable
		{
			private TState _state;

			private Func<TState, TState> _action;

			private volatile bool _disposed;

			public FastPeriodicTimer(TState state, Func<TState, TState> action)
			{
				_state = state;
				_action = action;
				ThreadPool.QueueUserWorkItem(delegate(object _)
				{
					Tick(_);
				}, this);
			}

			private static void Tick(object state)
			{
				FastPeriodicTimer<TState> fastPeriodicTimer = (FastPeriodicTimer<TState>)state;
				if (!fastPeriodicTimer._disposed)
				{
					fastPeriodicTimer._state = fastPeriodicTimer._action(fastPeriodicTimer._state);
					ThreadPool.QueueUserWorkItem(delegate(object _)
					{
						Tick(_);
					}, fastPeriodicTimer);
				}
			}

			public void Dispose()
			{
				_disposed = true;
				_action = Stubs<TState>.I;
			}
		}

		private sealed class PeriodicTimer<TState> : IDisposable
		{
			private TState _state;

			private Func<TState, TState> _action;

			private readonly AsyncLock _gate;

			private volatile System.Threading.Timer _timer;

			public PeriodicTimer(TState state, TimeSpan period, Func<TState, TState> action)
			{
				_state = state;
				_action = action;
				_gate = new AsyncLock();
				_timer = new System.Threading.Timer(delegate(object @this)
				{
					((PeriodicTimer<TState>)@this).Tick();
				}, this, period, period);
			}

			private void Tick()
			{
				_gate.Wait(this, delegate(PeriodicTimer<TState> @this)
				{
					@this._state = @this._action(@this._state);
				});
			}

			public void Dispose()
			{
				System.Threading.Timer timer = _timer;
				if (timer != null)
				{
					_action = Stubs<TState>.I;
					_timer = null;
					timer.Dispose();
					_gate.Dispose();
				}
			}
		}

		private static readonly Lazy<ThreadPoolScheduler> LazyInstance = new Lazy<ThreadPoolScheduler>(() => new ThreadPoolScheduler());

		private static readonly Lazy<NewThreadScheduler> LazyNewBackgroundThread = new Lazy<NewThreadScheduler>(() => new NewThreadScheduler((ThreadStart action) => new Thread(action)
		{
			IsBackground = true
		}));

		public static ThreadPoolScheduler Instance => LazyInstance.Value;

		private ThreadPoolScheduler()
		{
		}

		public override IDisposable Schedule<TState>(TState state, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			UserWorkItem<TState> userWorkItem = new UserWorkItem<TState>(this, state, action);
			ThreadPool.QueueUserWorkItem(delegate(object closureWorkItem)
			{
				((UserWorkItem<TState>)closureWorkItem).Run();
			}, userWorkItem);
			return userWorkItem;
		}

		public override IDisposable Schedule<TState>(TState state, TimeSpan dueTime, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			TimeSpan dueTime2 = Scheduler.Normalize(dueTime);
			if (dueTime2.Ticks == 0L)
			{
				return Schedule(state, action);
			}
			UserWorkItem<TState> userWorkItem = new UserWorkItem<TState>(this, state, action);
			userWorkItem.CancelQueueDisposable = new System.Threading.Timer(delegate(object closureWorkItem)
			{
				((UserWorkItem<TState>)closureWorkItem).Run();
			}, userWorkItem, dueTime2, Timeout.InfiniteTimeSpan);
			return userWorkItem;
		}

		public IDisposable ScheduleLongRunning<TState>(TState state, Action<TState, ICancelable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			return LazyNewBackgroundThread.Value.ScheduleLongRunning(state, action);
		}

		public override IStopwatch StartStopwatch()
		{
			return new StopwatchImpl();
		}

		public IDisposable SchedulePeriodic<TState>(TState state, TimeSpan period, Func<TState, TState> action)
		{
			if (period < TimeSpan.Zero)
			{
				throw new ArgumentOutOfRangeException("period");
			}
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			if (period == TimeSpan.Zero)
			{
				return new FastPeriodicTimer<TState>(state, action);
			}
			return new PeriodicTimer<TState>(state, period, action);
		}
	}
	internal sealed class UserWorkItem<TState> : IDisposable
	{
		private IDisposable _cancelRunDisposable;

		private IDisposable _cancelQueueDisposable;

		private readonly TState _state;

		private readonly IScheduler _scheduler;

		private readonly Func<IScheduler, TState, IDisposable> _action;

		public IDisposable CancelQueueDisposable
		{
			get
			{
				return Disposable.GetValue(ref _cancelQueueDisposable);
			}
			set
			{
				Disposable.SetSingle(ref _cancelQueueDisposable, value);
			}
		}

		public UserWorkItem(IScheduler scheduler, TState state, Func<IScheduler, TState, IDisposable> action)
		{
			_state = state;
			_action = action;
			_scheduler = scheduler;
		}

		public void Run()
		{
			if (!Disposable.GetIsDisposed(ref _cancelRunDisposable))
			{
				Disposable.SetSingle(ref _cancelRunDisposable, _action(_scheduler, _state));
			}
		}

		public void Dispose()
		{
			Disposable.TryDispose(ref _cancelQueueDisposable);
			Disposable.TryDispose(ref _cancelRunDisposable);
		}
	}
	public abstract class VirtualTimeSchedulerBase<TAbsolute, TRelative> : IScheduler, IServiceProvider, IStopwatchProvider where TAbsolute : IComparable<TAbsolute>
	{
		private sealed class VirtualTimeStopwatch : IStopwatch
		{
			private readonly Func<TimeSpan> _getElapsed;

			public TimeSpan Elapsed => _getElapsed();

			public VirtualTimeStopwatch(Func<TimeSpan> getElapsed)
			{
				_getElapsed = getElapsed;
			}
		}

		public bool IsEnabled { get; private set; }

		protected IComparer<TAbsolute> Comparer { get; }

		public TAbsolute Clock { get; protected set; }

		public DateTimeOffset Now => ToDateTimeOffset(Clock);

		protected VirtualTimeSchedulerBase()
			: this(default(TAbsolute), (IComparer<TAbsolute>)Comparer<TAbsolute>.Default)
		{
		}

		protected VirtualTimeSchedulerBase(TAbsolute initialClock, IComparer<TAbsolute> comparer)
		{
			Clock = initialClock;
			Comparer = comparer ?? throw new ArgumentNullException("comparer");
		}

		protected abstract TAbsolute Add(TAbsolute absolute, TRelative relative);

		protected abstract DateTimeOffset ToDateTimeOffset(TAbsolute absolute);

		protected abstract TRelative ToRelative(TimeSpan timeSpan);

		public abstract IDisposable ScheduleAbsolute<TState>(TState state, TAbsolute dueTime, Func<IScheduler, TState, IDisposable> action);

		public IDisposable ScheduleRelative<TState>(TState state, TRelative dueTime, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			TAbsolute dueTime2 = Add(Clock, dueTime);
			return ScheduleAbsolute(state, dueTime2, action);
		}

		public IDisposable Schedule<TState>(TState state, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			return ScheduleAbsolute(state, Clock, action);
		}

		public IDisposable Schedule<TState>(TState state, TimeSpan dueTime, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			return ScheduleRelative(state, ToRelative(dueTime), action);
		}

		public IDisposable Schedule<TState>(TState state, DateTimeOffset dueTime, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			return ScheduleRelative(state, ToRelative(dueTime - Now), action);
		}

		public void Start()
		{
			if (IsEnabled)
			{
				return;
			}
			IsEnabled = true;
			do
			{
				IScheduledItem<TAbsolute> next = GetNext();
				if (next != null)
				{
					if (Comparer.Compare(next.DueTime, Clock) > 0)
					{
						Clock = next.DueTime;
					}
					next.Invoke();
				}
				else
				{
					IsEnabled = false;
				}
			}
			while (IsEnabled);
		}

		public void Stop()
		{
			IsEnabled = false;
		}

		public void AdvanceTo(TAbsolute time)
		{
			int num = Comparer.Compare(time, Clock);
			if (num < 0)
			{
				throw new ArgumentOutOfRangeException("time");
			}
			if (num == 0)
			{
				return;
			}
			if (!IsEnabled)
			{
				IsEnabled = true;
				do
				{
					IScheduledItem<TAbsolute> next = GetNext();
					if (next != null && Comparer.Compare(next.DueTime, time) <= 0)
					{
						if (Comparer.Compare(next.DueTime, Clock) > 0)
						{
							Clock = next.DueTime;
						}
						next.Invoke();
					}
					else
					{
						IsEnabled = false;
					}
				}
				while (IsEnabled);
				Clock = time;
				return;
			}
			throw new InvalidOperationException(string.Format(CultureInfo.CurrentCulture, Strings_Linq.CANT_ADVANCE_WHILE_RUNNING, "AdvanceTo"));
		}

		public void AdvanceBy(TRelative time)
		{
			TAbsolute val = Add(Clock, time);
			int num = Comparer.Compare(val, Clock);
			if (num < 0)
			{
				throw new ArgumentOutOfRangeException("time");
			}
			if (num != 0)
			{
				if (IsEnabled)
				{
					throw new InvalidOperationException(string.Format(CultureInfo.CurrentCulture, Strings_Linq.CANT_ADVANCE_WHILE_RUNNING, "AdvanceBy"));
				}
				AdvanceTo(val);
			}
		}

		public void Sleep(TRelative time)
		{
			TAbsolute val = Add(Clock, time);
			if (Comparer.Compare(val, Clock) < 0)
			{
				throw new ArgumentOutOfRangeException("time");
			}
			Clock = val;
		}

		protected abstract IScheduledItem<TAbsolute> GetNext();

		object IServiceProvider.GetService(Type serviceType)
		{
			return GetService(serviceType);
		}

		protected virtual object GetService(Type serviceType)
		{
			if (serviceType == typeof(IStopwatchProvider))
			{
				return this;
			}
			return null;
		}

		public IStopwatch StartStopwatch()
		{
			DateTimeOffset start = ToDateTimeOffset(Clock);
			return new VirtualTimeStopwatch(() => ToDateTimeOffset(Clock) - start);
		}
	}
	public abstract class VirtualTimeScheduler<TAbsolute, TRelative> : VirtualTimeSchedulerBase<TAbsolute, TRelative> where TAbsolute : IComparable<TAbsolute>
	{
		private readonly SchedulerQueue<TAbsolute> _queue = new SchedulerQueue<TAbsolute>();

		protected VirtualTimeScheduler()
		{
		}

		protected VirtualTimeScheduler(TAbsolute initialClock, IComparer<TAbsolute> comparer)
			: base(initialClock, comparer)
		{
		}

		protected override IScheduledItem<TAbsolute> GetNext()
		{
			lock (_queue)
			{
				while (_queue.Count > 0)
				{
					ScheduledItem<TAbsolute> scheduledItem = _queue.Peek();
					if (scheduledItem.IsCanceled)
					{
						_queue.Dequeue();
						continue;
					}
					return scheduledItem;
				}
			}
			return null;
		}

		public override IDisposable ScheduleAbsolute<TState>(TState state, TAbsolute dueTime, Func<IScheduler, TState, IDisposable> action)
		{
			if (action == null)
			{
				throw new ArgumentNullException("action");
			}
			ScheduledItem<TAbsolute, TState> si = null;
			Func<IScheduler, TState, IDisposable> action2 = delegate(IScheduler scheduler, TState arg)
			{
				lock (_queue)
				{
					_queue.Remove(si);
				}
				return action(scheduler, arg);
			};
			si = new ScheduledItem<TAbsolute, TState>(this, state, action2, dueTime, base.Comparer);
			lock (_queue)
			{
				_queue.Enqueue(si);
			}
			return si;
		}
	}
	public static class VirtualTimeSchedulerExtensions
	{
		public static IDisposable ScheduleRelative<TAbsolute, TRelative>(this VirtualTimeSchedulerBase<TAbsolute, TRelative> scheduler, TRelative dueTime, Action action) where TAbsolute : IComparable<TAbsolute>
		{
			if (scheduler == null)
			{
